const body = $input.first().json.body;
const vehicle = body.vehicle || {};
const settings = body.settings || {};

return [{
  json: {
    event: 'setup_save',
    ownerName: settings.ownerName || vehicle.ownerName || 'Vehicle Owner',
    ownerEmail: settings.ownerEmail || vehicle.ownerEmail || '',
    vehicleMake: vehicle.make || '',
    vehicleModel: vehicle.model || '',
    vehicleYear: vehicle.year || '',
    fuelType: vehicle.fuelType || 'Petrol',
    regNumber: vehicle.regNumber || '',
    currentMileage: vehicle.currentMileage || 0,
    purchasePrice: vehicle.purchasePrice || 0,
    purchaseDate: vehicle.purchaseDate || '',
    engine: vehicle.engine || '',
    transmission: vehicle.transmission || 'Manual',
    color: vehicle.color || '',
    avgMonthlyKm: vehicle.avgMonthlyKm || 700,
    webhookUrl: settings.webhookUrl || '',
    savedAt: new Date().toISOString()
  }
}];

const body = $input.first().json.body;
const vehicle = body.vehicle || {};
const service = body.service || {};
const settings = body.settings || {};

const totalCost = (service.parts || 0) + (service.labour || 0);
const costPerKm = vehicle.currentMileage > 0 ? (totalCost / vehicle.currentMileage).toFixed(2) : '0.00';

return [{
  json: {
    event: 'service_add',
    ownerName: settings.ownerName || 'Vehicle Owner',
    ownerEmail: settings.ownerEmail || '',
    vehicleMake: vehicle.make || '',
    vehicleModel: vehicle.model || '',
    vehicleYear: vehicle.year || '',
    regNumber: vehicle.regNumber || '',
    currentMileage: vehicle.currentMileage || 0,
    serviceDate: service.date || new Date().toISOString().split('T')[0],
    serviceType: service.type || 'General Service',
    serviceCategory: service.category || 'routine',
    workshop: service.workshop || 'Not specified',
    mileageAtService: service.mileage || vehicle.currentMileage || 0,
    partsCost: service.parts || 0,
    labourCost: service.labour || 0,
    totalCost: totalCost,
    nextServiceKm: service.nextKm || 0,
    nextServiceDate: service.nextDate || '',
    notes: service.notes || '',
    invoiceRef: service.invoiceRef || '',
    costPerKm: costPerKm,
    loggedAt: new Date().toISOString()
  }
}];

const body = $input.first().json.body;
const vehicle = body.vehicle || {};
const services = body.services || [];
const costs = body.costs || {};
const health = body.health || {};
const resale = body.resale || {};
const maintenance = body.maintenance || {};
const patterns = body.patterns || {};
const question = body.question || 'Provide a full vehicle health and cost analysis.';
const settings = body.settings || {};

const serviceList = services.slice(0, 10).map((s, i) =>
  `${i+1}. ${s.date} – ${s.type} (₹${((s.parts||0)+(s.labour||0)).toLocaleString('en-IN')}) at ${s.workshop||'N/A'} [${s.mileage||0} km]`
).join('\n');

const analyticsPrompt = `You are AutoLog AI, an expert automotive analyst and vehicle health advisor specializing in Indian vehicles and the Indian market.

VEHICLE DATA:
═══════════════════════════════════
Vehicle: ${vehicle.year||''} ${vehicle.make||''} ${vehicle.model||''}
Registration: ${vehicle.regNumber||'N/A'}
Fuel: ${vehicle.fuelType||'N/A'} | Transmission: ${vehicle.transmission||'N/A'}
Engine: ${vehicle.engine||'N/A'} | Color: ${vehicle.color||'N/A'}
Current Mileage: ${(vehicle.currentMileage||0).toLocaleString('en-IN')} km
Purchase Price: ₹${(vehicle.purchasePrice||0).toLocaleString('en-IN')}
Purchase Date: ${vehicle.purchaseDate||'N/A'}
Avg Monthly Usage: ${vehicle.avgMonthlyKm||700} km/month

COST ANALYSIS:
Total Cost of Ownership: ₹${(costs.totalCost||0).toLocaleString('en-IN')}
Avg Monthly Cost: ₹${(costs.avgMonthlyCost||0).toLocaleString('en-IN')}
Cost per KM: ₹${costs.costPerKm||'0.00'}
Maintenance Ratio: ${costs.maintenanceRatio||0}%

HEALTH METRICS:
Health Score: ${health.score||0}/100
Verdict: ${health.verdict||'N/A'}

RESALE ESTIMATES:
Estimated Market Value: ₹${(resale.estimatedValue||0).toLocaleString('en-IN')}
Value Retained: ${resale.valueRetained||0}%
Depreciation Loss: ₹${(resale.depreciationLoss||0).toLocaleString('en-IN')}

MAINTENANCE STATUS:
Oil Change Overdue: ${maintenance.oilChangeDue ? 'YES ⚠️' : 'No'}
KM Since Last Oil Change: ${(maintenance.kmSinceOil||0).toLocaleString('en-IN')} km
Next Oil Service at: ${(maintenance.nextOilKm||0).toLocaleString('en-IN')} km

ISSUE PATTERNS:
Recurring Brake Issues: ${patterns.brakeRecurring ? 'YES ⚠️' : 'No'}
Total Brake Services: ${patterns.brakeCount||0}
Recent Brake Services (90d): ${patterns.recentBrakes||0}

SERVICE HISTORY (Last 10 records):
${serviceList||'No service records found.'}

USER QUESTION: ${question}

Analysis rules:
- Use ₹ for all monetary values (Indian Rupees)
- Be direct, specific, and data-driven
- Flag recurring issues and maintenance patterns
- Consider Indian road conditions and service intervals
- Compare against benchmarks for Indian vehicles
- Always end with 3 prioritized ACTION ITEMS
- Format response clearly with sections`;

return [{
  json: {
    analyticsPrompt,
    ownerEmail: settings.ownerEmail || '',
    ownerName: settings.ownerName || 'Vehicle Owner',
    vehicleMake: vehicle.make || '',
    vehicleModel: vehicle.model || '',
    regNumber: vehicle.regNumber || '',
    question,
    requestedAt: new Date().toISOString()
  }
}];

const promptData = $('Build AI Analytics Prompt').first().json;
const agentOutput = $input.first().json;
const aiText = agentOutput.output || 'AI analysis unavailable.';

return [{
  json: {
    success: true,
    event: 'ai_analytics',
    aiResponse: aiText,
    question: promptData.question,
    ownerEmail: promptData.ownerEmail,
    ownerName: promptData.ownerName,
    vehicleMake: promptData.vehicleMake,
    vehicleModel: promptData.vehicleModel,
    regNumber: promptData.regNumber,
    model: 'llama-3.3-70b-versatile',
    generatedAt: new Date().toISOString()
  }
}];

const body = $input.first().json.body;
const vehicle = body.vehicle || {};
const services = body.services || [];
const userMessage = body.message || '';
const chatHistory = body.history || [];
const settings = body.settings || {};
const costs = body.costs || {};
const health = body.health || {};
const maintenance = body.maintenance || {};
const reminders = body.reminders || [];
const patterns = body.patterns || {};
const resale = body.resale || {};

const serviceList = services.slice(0, 8).map((s, i) =>
  `${s.date}: ${s.type} (₹${((s.parts||0)+(s.labour||0)).toLocaleString('en-IN')}) – ${s.workshop||'N/A'} [${s.mileage||0} km]`
).join('\n');

const dueReminders = reminders.filter(r => !r.done && (r.date || r.km)).slice(0, 5);
const reminderList = dueReminders.map(r => `- ${r.title||r.type}: ${r.date ? 'Due '+r.date : ''} ${r.km ? 'at '+r.km+' km' : ''}`).join('\n');

const systemPrompt = `You are AutoLog Assistant, a friendly, knowledgeable AI chatbot and personal car advisor embedded in the AutoLog vehicle management app.

=== VEHICLE PROFILE ===
Vehicle: ${vehicle.year||''} ${vehicle.make||''} ${vehicle.model||''} (${vehicle.regNumber||'N/A'})
Fuel: ${vehicle.fuelType||'N/A'} | Engine: ${vehicle.engine||'N/A'} | Transmission: ${vehicle.transmission||'N/A'}
Color: ${vehicle.color||'N/A'} | Purchase Date: ${vehicle.purchaseDate||'N/A'}
Purchase Price: ₹${(vehicle.purchasePrice||0).toLocaleString('en-IN')}
Current Mileage: ${(vehicle.currentMileage||0).toLocaleString('en-IN')} km
Avg Monthly Usage: ${vehicle.avgMonthlyKm||700} km/month

=== HEALTH & COSTS ===
Health Score: ${health.score||0}/100 (${health.verdict||'Unknown'})
Total Cost of Ownership: ₹${(costs.totalCost||0).toLocaleString('en-IN')}
Avg Monthly Cost: ₹${(costs.avgMonthlyCost||0).toLocaleString('en-IN')}
Cost per KM: ₹${costs.costPerKm||'0.00'}
Total Services Logged: ${services.length}

=== MAINTENANCE STATUS ===
Oil Change Overdue: ${maintenance.oilChangeDue ? 'YES ⚠️' : 'No'}
KM Since Last Oil Change: ${(maintenance.kmSinceOil||0).toLocaleString('en-IN')} km
Next Oil Service at: ${(maintenance.nextOilKm||0).toLocaleString('en-IN')} km
Recurring Brake Issues: ${patterns.brakeRecurring ? 'YES ⚠️ ('+patterns.brakeCount+' times)' : 'No'}

=== RESALE ===
Estimated Market Value: ₹${(resale.estimatedValue||0).toLocaleString('en-IN')}
Value Retained: ${resale.valueRetained||0}% | Depreciation: ₹${(resale.depreciationLoss||0).toLocaleString('en-IN')}

=== PENDING REMINDERS ===
${reminderList || 'No pending reminders.'}

=== RECENT SERVICE HISTORY ===
${serviceList || 'No service records yet.'}

=== YOUR PERSONALITY ===
- Friendly, conversational, and reassuring
- Use clear non-technical language unless the user asks for details
- Always use ₹ for Indian Rupees
- Always reference the owner's actual vehicle data when relevant
- Keep answers concise (2–4 paragraphs max for most queries)
- Add a helpful tip or reminder when appropriate
- Give repair cost estimates relevant to the Indian market
- For safety issues, always prioritize safety over cost
- You have full context of the car's profile, costs, health, reminders, and service history — use it!`;

const historyMessages = chatHistory.slice(-8).map(h => ({ role: h.role, content: h.content }));

return [{
  json: {
    systemPrompt,
    historyMessages,
    userMessage,
    fullPrompt: userMessage,
    ownerEmail: settings.ownerEmail || '',
    vehicleMake: vehicle.make || '',
    vehicleModel: vehicle.model || '',
    requestedAt: new Date().toISOString()
  }
}];

const agentOutput = $input.first().json;
const aiReply = agentOutput.output || 'I could not process your request. Please try again.';

return [{
  json: {
    success: true,
    event: 'ai_chat',
    reply: aiReply,
    model: 'llama-3.1-8b-instant',
    generatedAt: new Date().toISOString()
  }
}];

const body = $input.first().json.body;
const vehicle = body.vehicle || {};
const reminders = body.reminders || [];
const settings = body.settings || {};
const maintenance = body.maintenance || {};
const health = body.health || {};

const now = new Date();

const dueReminders = reminders.filter(r => {
  if (!r.date && !r.km) return false;
  if (r.done) return false;
  if (r.date) { const diff = (new Date(r.date) - now) / (1000*60*60*24); return diff <= 7; }
  if (r.km && vehicle.currentMileage) { return (r.km - vehicle.currentMileage) <= 500; }
  return false;
});

const urgentReminders = dueReminders.filter(r => {
  if (r.date) { const diff = (new Date(r.date) - now) / (1000*60*60*24); return diff <= 2; }
  if (r.km && vehicle.currentMileage) { return (r.km - vehicle.currentMileage) <= 100; }
  return false;
});

const maintenanceAlerts = [];
if (maintenance.oilChangeDue) {
  maintenanceAlerts.push({ title: '🔴 Oil Change OVERDUE', detail: `${(maintenance.kmSinceOil||0).toLocaleString('en-IN')} km since last oil change. Service immediately!` });
}
if (maintenance.nextOilKm && vehicle.currentMileage) {
  const remaining = maintenance.nextOilKm - vehicle.currentMileage;
  if (remaining > 0 && remaining <= 500) {
    maintenanceAlerts.push({ title: '🟡 Oil Change Due Soon', detail: `${remaining.toLocaleString('en-IN')} km remaining until next oil change.` });
  }
}

return [{
  json: {
    event: 'reminder_check',
    ownerEmail: settings.ownerEmail || '',
    ownerName: settings.ownerName || 'Vehicle Owner',
    vehicleMake: vehicle.make || '',
    vehicleModel: vehicle.model || '',
    regNumber: vehicle.regNumber || '',
    currentMileage: vehicle.currentMileage || 0,
    healthScore: health.score || 0,
    healthVerdict: health.verdict || 'Unknown',
    dueReminders,
    urgentReminders,
    maintenanceAlerts,
    totalDue: dueReminders.length,
    hasUrgent: urgentReminders.length > 0,
    hasAlerts: maintenanceAlerts.length > 0,
    checkedAt: new Date().toISOString()
  }
}];

const body = $input.first().json.body;
const vehicle = body.vehicle || {};
const services = body.services || [];
const costs = body.costs || {};
const maintenance = body.maintenance || {};
const health = body.health || {};
const resale = body.resale || {};
const patterns = body.patterns || {};
const settings = body.settings || {};

const vehicleAge = vehicle.year ? (new Date().getFullYear() - vehicle.year) : 0;
const avgServiceCost = services.length > 0 ? Math.round(costs.totalCost / services.length) : 0;
const lastService = services.length > 0 ? [...services].sort((a,b) => new Date(b.date)-new Date(a.date))[0] : null;

return [{
  json: {
    syncType: 'manual_full_sync',
    ownerName: settings.ownerName || vehicle.ownerName || 'Vehicle Owner',
    ownerEmail: settings.ownerEmail || vehicle.ownerEmail || '',
    vehicleSummary: `${vehicle.year||''} ${vehicle.make||''} ${vehicle.model||''} (${vehicle.regNumber||'N/A'})`,
    vehicleMake: vehicle.make || '',
    vehicleModel: vehicle.model || '',
    vehicleYear: vehicle.year || '',
    regNumber: vehicle.regNumber || '',
    fuelType: vehicle.fuelType || '',
    currentMileage: vehicle.currentMileage || 0,
    vehicleAge,
    avgMonthlyKm: vehicle.avgMonthlyKm || 700,
    purchasePrice: vehicle.purchasePrice || 0,
    purchaseDate: vehicle.purchaseDate || '',
    engine: vehicle.engine || '',
    transmission: vehicle.transmission || '',
    totalCost: costs.totalCost || 0,
    avgMonthlyCost: costs.avgMonthlyCost || 0,
    costPerKm: costs.costPerKm || 0,
    maintenanceRatio: costs.maintenanceRatio || 0,
    totalServices: services.length,
    avgServiceCost,
    lastServiceType: lastService ? lastService.type : 'N/A',
    lastServiceDate: lastService ? lastService.date : 'N/A',
    healthScore: health.score || 0,
    healthVerdict: health.verdict || 'Unknown',
    oilChangeDue: maintenance.oilChangeDue || false,
    kmSinceOil: maintenance.kmSinceOil || 0,
    nextOilKm: maintenance.nextOilKm || 0,
    brakeIssueDetected: patterns.brakeRecurring || false,
    brakeCount: patterns.brakeCount || 0,
    estimatedResaleValue: resale.estimatedValue || 0,
    valueRetained: resale.valueRetained || 0,
    depreciationLoss: resale.depreciationLoss || 0,
    syncedAt: new Date().toISOString()
  }
}];

parameters.text:
=Generate a sync summary report for this vehicle data:

Vehicle: {{ $json.vehicleSummary }}
Mileage: {{ $json.currentMileage }} km | Age: {{ $json.vehicleAge }} years
Health Score: {{ $json.healthScore }}/100 ({{ $json.healthVerdict }})

Financials:
- Total Cost: ₹{{ $json.totalCost }}
- Monthly Avg: ₹{{ $json.avgMonthlyCost }}
- Cost/km: ₹{{ $json.costPerKm }}
- Services: {{ $json.totalServices }} (avg ₹{{ $json.avgServiceCost }} each)

Maintenance:
- Oil Change Overdue: {{ $json.oilChangeDue ? 'YES - URGENT' : 'No' }}
- KM Since Oil: {{ $json.kmSinceOil }} km
- Brake Issues Detected: {{ $json.brakeIssueDetected ? 'YES (' + $json.brakeCount + ' occurrences)' : 'No' }}

Resale:
- Estimated Value: ₹{{ $json.estimatedResaleValue }}
- Value Retained: {{ $json.valueRetained }}%
- Depreciation: ₹{{ $json.depreciationLoss }}

Last Service: {{ $json.lastServiceType }} on {{ $json.lastServiceDate }}

Provide: 1) Health assessment 2) Top 3 concerns 3) Financial efficiency rating 4) Immediate action items. Keep under 400 words.

